//have to include XMLHttpRequest as soon as possible
if (!(global as any).XMLHttpRequest) {
    (global as any).XMLHttpRequest = require('xmlhttprequest').XMLHttpRequest;
    //provide a 'response' property that does what we expect
    Object.defineProperty((global as any).XMLHttpRequest.prototype, 'response', {
        get: function() {
            if (this.responseType === 'json') {
                try {
                    this.__response = JSON.parse(this.responseText);
                } catch (e) {
                    //don't try to parse it as JSON next time someone tries to get the response
                    this.responseType = null;
                }
            }
            if (this.__response) {
                return this.__response;
            }
            return this.responseXML || this.responseText;
        }
    });
}
import {Log} from 'jibo-log';
import async = require('async');
import {ServiceContainer, ServiceOwner} from './utils/ServiceOwner';
import {ServiceRecord, InitCallback} from './utils/Types';

const log = new Log('SF.ServiceClients');

interface ServiceInit {
    (service:ServiceRecord, parentLog:Log, callback:InitCallback):void;
}

//dictionary of init functions keyed by name found in service registry
const services:{[name:string]:ServiceInit} = {};


import {lps} from './services/LPSService';
export {lps};
services.lps = lps.init;


export type AsyncMethod = (callback:Function) => void;

export function init(
    owner:ServiceContainer,
    records:ServiceRecord[],
    callback:InitCallback,
    initWrapper?:(initFunction:AsyncMethod, service:string) => AsyncMethod) {
    //init our access to outside variables
    ServiceOwner.init(owner);

    const tasks = [];
    //go through each service that we want to init and add a init task
    records.forEach((service) => {
        const initFunction = services[service.name];
        if(initFunction) {
            //wrap the init method to include the service data and the parent log
            let actualInit = (callback:() => void) => {
                initFunction(service, log, callback);
            };
            //if there is an init wrapper, then wrap our init methods so that anyone that cares
            //can time how long initialization takes
            if (initWrapper) {
                actualInit = initWrapper(actualInit, service.name);
            }
            tasks.push(actualInit);
        }
    });
    //actually initialize all of the services
    async.parallel(tasks, callback);
}
